import{_ as i,o as s,c as l,ae as t,j as e}from"./chunks/framework.C7qU-Vik.js";const h=JSON.parse('{"title":"Algebra de audiencias cifradas.","description":"","frontmatter":{},"headers":[],"relativePath":"es/Algebra de audiencias cifradas.md","filePath":"es/Algebra de audiencias cifradas.md"}'),n={name:"es/Algebra de audiencias cifradas.md"};function o(c,a,d,r,p,u){return s(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="algebra-de-audiencias-cifradas" tabindex="-1"><strong>Algebra de audiencias cifradas</strong>. <a class="header-anchor" href="#algebra-de-audiencias-cifradas" aria-label="Permalink to &quot;**Algebra de audiencias cifradas**.&quot;">​</a></h1><p><strong>Actualización NRP:</strong> el mesh actual separa explícitamente topología y decisión. <code>claimed_namespaces</code> y <code>tags</code> describen el conjunto topológico rápido (<code>T</code>: qué monads pueden cargar/servir algo). La capa abierta <code>_.mesh.monads.&lt;id&gt;.claimed.&lt;namespace&gt;</code> guarda señales de decisión (<code>resonance</code>, <code>avgLatencyMs</code>, <code>effectiveResonance</code>, etc.) sin cerrar el schema. La audiencia criptográfica (<code>A</code>) sigue siendo independiente: que un monad pueda transportar o servir un path no significa que pueda abrir su contenido.</p><ul><li>el context define <strong>dónde/cuáles nodos</strong></li><li>la capability define <strong>qué acción está permitida</strong></li><li>la encryption define <strong>quién puede abrir ese contenido</strong></li></ul><p>La forma matemática sería separar tres sets:</p><ul><li><p>T = <strong>topology set</strong></p><ul><li>en qué nodos vive o se replica el ciphertext</li></ul></li><li><p>A = <strong>audience set</strong></p><ul><li>qué identidades pueden descifrar</li></ul></li><li><p>P = <strong>procedure/capability set</strong></p><ul><li>qué acciones pueden ejecutar sobre eso</li></ul><p>Entonces una “encrypted island” sería algo así:</p></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Island I = (path, ciphertext, T, A, P)</span></span></code></pre></div><p>Ejemplo:</p><ul><li><p>imagen guardada en:</p><ul><li>office-node</li><li>iphone</li><li>backup-daemon</li></ul><p>Eso es:</p></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T = {office, iphone, backup}</span></span></code></pre></div><p>Pero solo tú y tu esposa pueden abrirla:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A = {me, wife}</span></span></code></pre></div><p>Entonces sí:</p><ul><li><strong>muchos nodos pueden guardar la isla</strong></li><li>pero solo un subconjunto puede leerla</li></ul><hr><p>A clean way to hold it is:</p><ul><li>space is the primary thing</li><li>the rest are predicates or projections over that space</li><li>everything is refinement, union, intersection, membership, replication</li></ul><p>So:</p><ul><li>public space = its readable audience approaches the open set</li><li>private space = audience is tightly bounded, often <code>{self}</code></li><li>shared space = audience is a union like <code>{me ∪ wife ∪ ...}</code></li><li>encrypted space = membership in the readable audience is enforced cryptographically</li><li>replicated space = the topology set has multiple carriers</li><li>local space, remote space, hosted space = just different topology bindings</li></ul><p>You can even write it as one space with different sets:</p><ul><li>A = audience set</li><li>T = topology set</li><li>C = capability/action set</li><li>P = path/subspace set</li></ul><p>Then the adjectives are just statements about those sets:</p>',21),e("ul",null,[e("li",{self:""},"private: A ="),e("li",null,"shared: |A| > 1"),e("li",null,"encrypted: access to A is cryptographically enforced"),e("li",null,"replicated: |T| > 1"),e("li",null,"public: A is open or broadly readable")],-1)])])}const b=i(n,[["render",o]]);export{h as __pageData,b as default};
